void center_print(const char *s, int width)
{
	int length = strlen(s);
	int i;
	for (i=0; i<=(width-length)/2; i++) {
		fputs(" ", stdout);
	}
	fputs(s, stdout);
	fputs("\n", stdout);
}

void border_print(void)
{
	printf(
	"==================================================================="
	"=============\n");
}

void fancy_int( int a )
{
    if( a < 1000 )
        printf("%d\n",a);

    else if( a >= 1000 && a < 1000000 )
        printf("%d,%03d\n", a / 1000, a % 1000);

    else if( a >= 1000000 && a < 1000000000 )
        printf("%d,%03d,%03d\n", a / 1000000, (a % 1000000) / 1000, a % 1000 );

    else if( a >= 1000000000 )
        printf("%d,%03d,%03d,%03d\n",
               a / 1000000000,
               (a % 1000000000) / 1000000,
               (a % 1000000) / 1000,
               a % 1000 );
    else
        printf("%d\n",a);
}

Input read_CLI( int argc, char * argv[] )
{
	Input input;

	input.simulation_method = HISTORY_BASED;
	input.nthreads = 1;
	input.n_nuclides = 355;
	input.particles = 300000;
	input.lookups = 34;
	input.HM = LARGE;
	input.avg_n_poles = 1000;
	input.avg_n_windows = 100;
	input.numL = 4;
	input.doppler = 1;
	input.kernel_id = 0;

	g_platform_id = -1;
	g_device_id = -1;

	int default_lookups = 1;
	int default_particles = 1;

	for( int i = 1; i < argc; i++ )
	{
		char * arg = argv[i];

		if( strcmp(arg, "-m") == 0 )
		{
			char * sim_type = NULL;
			if( ++i < argc )
				sim_type = argv[i];
			else
				print_CLI_error();

			if( strcmp(sim_type, "history") == 0 )
				input.simulation_method = HISTORY_BASED;
			else if( strcmp(sim_type, "event") == 0 )
			{
				input.simulation_method = EVENT_BASED;
				if( default_lookups && default_particles )
				{
					input.lookups =  input.lookups * input.particles;
					input.particles = 0;
				}
			}
			else
				print_CLI_error();
		}
		else if( strcmp(arg, "-l") == 0 )
		{
			if( ++i < argc )
			{
				input.lookups = atoi(argv[i]);
				default_lookups = 0;
			}
			else
				print_CLI_error();
		}
		else if( strcmp(arg, "-p") == 0 )
		{
			if( ++i < argc )
			{
				input.particles = atoi(argv[i]);
				default_particles = 0;
			}
			else
				print_CLI_error();
		}
		else if( strcmp(arg, "-n") == 0 )
		{
			if( ++i < argc )
				input.n_nuclides = atoi(argv[i]);
			else
				print_CLI_error();
		}
		else if( strcmp(arg, "-s") == 0 )
		{
			if( ++i < argc )
			{
				if( strcmp(argv[i], "small") == 0 )
					input.HM = SMALL;
				else if ( strcmp(argv[i], "large") == 0 )
					input.HM = LARGE;
				else
					print_CLI_error();
			}
			else
				print_CLI_error();
		}
		else if( strcmp(arg, "-d") == 0 )
		{
			input.doppler = 0;
		}
		else if( strcmp(arg, "-W") == 0 )
		{
			if( ++i < argc )
				input.avg_n_windows = atoi(argv[i]);
			else
				print_CLI_error();
		}
		else if( strcmp(arg, "-p") == 0 )
		{
			if( ++i < argc )
				input.avg_n_poles = atoi(argv[i]);
			else
				print_CLI_error();
		}
		else if( strcmp(arg, "-k") == 0 )
		{
			if( ++i < argc )
				input.kernel_id = atoi(argv[i]);
			else
				print_CLI_error();
		}
		else if( strcmp(arg, "-P") == 0 )
		{
			if( ++i < argc )
			{
				g_platform_id = atoi(argv[i]);
				printf("PLATFORM ID DETECTED = %d\n", g_platform_id);
			}
			else
				print_CLI_error();
		}
		else if( strcmp(arg, "-D") == 0 )
		{
			if( ++i < argc )
				g_device_id = atoi(argv[i]);
			else
				print_CLI_error();
		}
		else
			print_CLI_error();
	}

	if( input.nthreads < 1 )
		print_CLI_error();

	if( input.n_nuclides < 1 )
		print_CLI_error();

	if( input.lookups < 1 )
		print_CLI_error();

	if( input.avg_n_poles < 1 )
		print_CLI_error();

	if( input.avg_n_windows < 1 )
		print_CLI_error();

	if( input.HM == SMALL )
		input.n_nuclides = 68;

	return input;
}

void print_CLI_error(void)
{
	printf("Usage: ./multibench <options>\n");
	printf("Options include:\n");
	printf("  -s <size>        Size of H-M Benchmark to run (small, large)\n");
	printf("  -l <lookups>     Number of Cross-section (XS) lookups per particle history\n");
	printf("  -p <particles>   Number of particle histories\n");
	printf("  -P <poles>       Average Number of Poles per Nuclide\n");
	printf("  -W <poles>       Average Number of Windows per Nuclide\n");
	printf("  -d               Disables Temperature Dependence (Doppler Broadening)\n");
	printf("  -P <platform id> Manually specify the OpenCL platform id to run on\n");
	printf("  -D <device id>   Manually specify the OpenCL device id to run on\n");
	printf("Default is equivalent to: -s large -l 34 -p 300000 -P 1000 -W 100\n");
	printf("See readme for full description of default run values\n");
	exit(4);
}

void print_input_summary(Input input)
{
	size_t mem = get_mem_estimate(input);

	printf("Programming Model:           OpenCL\n");
	if( input.simulation_method == EVENT_BASED )
		printf("Simulation Method:           Event Based\n");
	else
		printf("Simulation Method:           History Based\n");
	printf("Materials:                   12\n");
	printf("H-M Benchmark Size:          ");
	if( input.HM == 0 )
		printf("Small\n");
	else
		printf("Large\n");
	if( input.doppler == 1 )
		printf("Temperature Dependence:      ON\n");
	else
		printf("Temperature Dependence:      OFF\n");
	printf("Total Nuclides:              %d\n", input.n_nuclides);
	printf("Avg Poles per Nuclide:       "); fancy_int(input.avg_n_poles);
	printf("Avg Windows per Nuclide:     "); fancy_int(input.avg_n_windows);

	int lookups = input.lookups;
	if( input.simulation_method == HISTORY_BASED )
	{
		printf("Particles:                   "); fancy_int(input.particles);
		printf("XS Lookups per Particle:     "); fancy_int(input.lookups);
		lookups *= input.particles;
	}
	printf("Total XS Lookups:            "); fancy_int(lookups);
	printf("Est. Memory Usage (MB):      %.1lf\n", mem / 1024.0 / 1024.0);

	if( g_platform_id == -1 )
		printf("OpenCL Platform ID:          Default\n");
	else
		printf("OpenCL Platform ID:          %d\n", g_platform_id);

	if( g_device_id == -1 )
		printf("OpenCL Device ID:            Default\n");
	else
		printf("OpenCL Device ID:            %d\n", g_device_id);
}

int validate_and_print_results(Input input, double runtime, unsigned long vhash, double sim_runtime)
{
	int lookups = 0;
	if( input.simulation_method == HISTORY_BASED )
		lookups = input.lookups*input.particles;
	else
		lookups = input.lookups;
	int lookups_per_sec = (int) ((double) lookups / runtime);
	int sim_only_lookups_per_sec = (int) ((double) lookups / sim_runtime);
	printf("NOTE: Timings are estimated -- use nvprof/nsys/iprof/rocprof for formal analysis\n");
	printf("Total Time Statistics (OpenCL Init / JIT Compilation + Simulation Kernel)\n");
	printf("Runtime:     %.3lf seconds\n", runtime);
	printf("Lookups:     "); fancy_int(lookups);
	printf("Lookups/s:   ");
	fancy_int(lookups_per_sec);
	printf("Simulation Kernel Only Statistics\n");
	printf("Runtime:     %.3lf seconds\n", sim_runtime);
	printf("Lookups/s:   ");
	fancy_int(sim_only_lookups_per_sec);

	int is_invalid = 1;

	unsigned long long large = 0;
	unsigned long long small = 0;
	if(input.simulation_method == HISTORY_BASED )
	{
		large = 351485;
		small = 879693;
	}
	else if( input.simulation_method == EVENT_BASED )
	{
		large = 358389;
		small = 880018;
	}

	if( input.HM  == LARGE )
	{
		if( vhash == large )
		{
			printf("Verification checksum: %lu (Valid)\n", vhash);
			is_invalid = 0;
		}
		else
			printf("Verification checksum: %lu (WARNING - INAVALID CHECKSUM!)\n", vhash);
	}
	else if( input.HM  == SMALL )
	{
		if( vhash == small )
		{
			printf("Verification checksum: %lu (Valid)\n", vhash);
			is_invalid = 0;
		}
		else
			printf("Verification checksum: %lu (WARNING - INAVALID CHECKSUM!)\n", vhash);
	}

	return is_invalid;
}

int validate_and_print_results(Input input, double runtime, unsigned long vhash)
{
	return validate_and_print_results(input, runtime, vhash, runtime);
}
